import{b as l,J as t,g as i,j as e}from"./chunks/framework.BFn5dPDD.js";const g=JSON.parse('{"title":"동호 배치 현황","description":"","frontmatter":{},"headers":[],"relativePath":"contract/status.md","filePath":"contract/status.md","lastUpdated":1779941493000}'),o={name:"contract/status.md"};function r(n,a,s,u,d,c){return t(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="동호-배치-현황" tabindex="-1">동호 배치 현황 <a class="header-anchor" href="#동호-배치-현황" aria-label="Permalink to &quot;동호 배치 현황&quot;">​</a></h1><p>프로젝트의 동호수별 계약 현황을 시각적으로 확인하고, 전체적인 청약 및 계약 요약 정보를 제공하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>계약 관리 &gt; 동호 배치 현황</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>각 동(건물)별, 층별, 라인별 유닛의 현재 상태(공실, 청약, 계약, 홀딩)를 색상으로 구분하여 직관적으로 파악할 수 있습니다. 전체 프로젝트의 청약 및 계약 현황 요약 정보와 함께, 계약자명 표시 여부 및 엑셀 출력 기능을 제공합니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li>프로젝트별 청약 및 계약 현황 요약 정보 제공</li><li>동호수 배치도를 통한 유닛별 상태 시각화 (공실, 청약, 계약, 홀딩)</li><li>동(건물)별 유닛 배치도 동적 로딩 (Lazy Loading)</li><li>계약자명 표시/숨김 토글 기능</li><li>동호수 현황표 엑셀 출력 기능</li><li>유닛 클릭 시 해당 계약자의 상세 정보로 이동 (계약자명 표시 시)</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-계약-현황-요약-contsummary-vue" tabindex="-1">1. 계약 현황 요약 (<code>ContSummary.vue</code>) <a class="header-anchor" href="#_1-계약-현황-요약-contsummary-vue" aria-label="Permalink to &quot;1. 계약 현황 요약 (`ContSummary.vue`)&quot;">​</a></h3><p>현재 프로젝트의 전체적인 청약 및 계약 현황을 요약하여 보여줍니다.</p><h4 id="주요-표시-항목" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><ul><li>총 세대수</li><li>청약 세대수</li><li>계약 세대수</li><li>동호 미배정 세대수</li><li>홀딩 세대수</li><li>합계 (청약 + 계약 세대수)</li><li>잔여 세대수</li><li>타입별 색상 범례</li></ul><h3 id="_2-동호수-현황표-tabletitlerow-vue-contractboard-vue" tabindex="-1">2. 동호수 현황표 (<code>TableTitleRow.vue</code>, <code>ContractBoard.vue</code>) <a class="header-anchor" href="#_2-동호수-현황표-tabletitlerow-vue-contractboard-vue" aria-label="Permalink to &quot;2. 동호수 현황표 (`TableTitleRow.vue`, `ContractBoard.vue`)&quot;">​</a></h3><p>프로젝트의 각 동(건물)별 동호수 배치도를 시각적으로 표시합니다. 각 유닛은 현재 상태에 따라 다른 색상으로 표시됩니다.</p><h4 id="주요-기능-1" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능-1" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h4><ul><li><strong>엑셀 출력 버튼</strong>: 현재 동호수 현황표를 엑셀 파일로 다운로드합니다.</li><li><strong>계약자명 표시 토글</strong>: 동호수 배치도에 계약자명을 표시하거나 숨길 수 있습니다.</li><li><strong>동(건물)별 배치도 (<code>LazyBuilding.vue</code>, <code>Building.vue</code>)</strong>: <ul><li>각 동(건물)의 층별, 라인별 유닛을 그리드 형태로 표시합니다.</li><li><code>LazyBuilding.vue</code>를 통해 화면에 보이는 동만 로딩하여 성능을 최적화합니다.</li><li><strong>유닛 (<code>Unit.vue</code>)</strong>: <ul><li>각 개별 유닛의 상태를 색상으로 표시합니다.</li><li><strong>색상 구분</strong>: <ul><li><strong>공실</strong>: 배경색 없음 (또는 기본색)</li><li><strong>청약</strong>: 연한 노란색 계열</li><li><strong>계약</strong>: 연한 회색 계열</li><li><strong>홀딩</strong>: 진한 회색 계열</li><li><strong>타입별 색상</strong>: 유닛 타입에 따라 다른 색상으로 유닛명 배경 표시</li></ul></li><li><strong>표시 정보</strong>: 유닛명, (옵션) 계약자명, 홀딩 사유 (툴팁)</li><li><strong>기능</strong>: 계약자명 클릭 시 해당 계약자의 상세 정보 페이지로 이동.</li><li><strong>피로티</strong>: 피로티 층은 별도의 배경색으로 표시.</li></ul></li></ul></li></ul>',16)])])}const m=l(o,[["render",r]]);export{g as __pageData,m as default};
